example.code:
export const getStaticProps: GetStaticProps<Props> = async ({ params }) => {
  const product = await fetchProduct(params?.slug as string);
  if (!product) return { notFound: true };
  return { props: { product }, revalidate: 3600 };
};

import Link from 'next/link';
// Next.js 13+
<Link href={`/products/${product.slug}`}>{product.name}</Link>
// External links
<a href="https://external.com" rel="noopener noreferrer" target="_blank">
  External
</a>

const productSchema = {
  '@context': 'https://schema.org',
  '@type': 'Product',
  name: product.name,
  description: product.description,
  image: product.images,
  sku: product.sku,
  brand: { '@type': 'Brand', name: product.brand },
  offers: {
    '@type': 'Offer',
    url: `https://example.com/products/${product.slug}`,
    priceCurrency: 'USD',
    price: product.price,
    availability: product.inStock
      ? 'https://schema.org/InStock'
      : 'https://schema.org/OutOfStock',
    seller: { '@type': 'Organization', name: 'Example Store' }
  },
  aggregateRating: product.rating ? {
    '@type': 'AggregateRating',
    ratingValue: product.rating.average,
    reviewCount: product.rating.count
  } : undefined
};

const breadcrumbSchema = {
  '@context': 'https://schema.org',
  '@type': 'BreadcrumbList',
  itemListElement: items.map((item, index) => ({
    '@type': 'ListItem',
    position: index + 1,
    name: item.name,
    item: item.url
  }))
};

import Image from 'next/image';
import dynamic from 'next/dynamic';

// LCP image: priority eager load
<Image
  src={product.image}
  alt={product.name}
  width={400}
  height={400}
  priority={true}
  placeholder="blur"
  blurDataURL={product.blurDataUrl}
/>

// Non-critical below-fold widget
const CommentsSection = dynamic(() => import('./Comments'), {
  loading: () => <Skeleton />,
  ssr: false
});

